#include <vector>
#include <unordered_map>
#include <algorithm>

std::vector<long long> solve(std::vector<long long> order, std::vector<long long> friends) {
    std::unordered_map<long long, int> order_map;
    for (int i = 0; i < order.size(); ++i) {
        order_map[order[i]] = i;
    }

    std::vector<std::pair<int, long long>> friend_order;
    for (long long id : friends) {
        friend_order.emplace_back(order_map[id], id);
    }

    std::sort(friend_order.begin(), friend_order.end());

    std::vector<long long> result;
    for (const auto& pair : friend_order) {
        result.push_back(pair.second);
    }

    return result;
}
